          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Base premium: 100G, first insurance surcharge: +10% = 110G, processing fee: +5G = 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should calculate base premium for other item types (amulet, staff, potion)");
    it.todo("should calculate base premium for a single component");
    it.todo("should apply special premium for a building block of 3 alike components");
    it.todo("should apply 50% cursed item surcharge");
    it.todo("should apply 30% surcharge for enchantment level >= 5");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years");
    it.todo("should apply 10% initial assessment surcharge for first insurance");
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should quote multiple items in a single policy");
  });

  describe("Claims", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment >= 8");
    it.todo("should fully reimburse damage to dragon material items");
  });
});

