const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const INITIAL_ASSESSMENT_RATE = 0.1;
const PROCESSING_FEE = 5;

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    const initialAssessmentSurcharge = Math.ceil(basePremium * INITIAL_ASSESSMENT_RATE);
    const premium = basePremium + initialAssessmentSurcharge + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

