const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;
const INITIAL_ASSESSMENT_RATE = 0.1;
const PROCESSING_FEE = 5;

function calculateBasePremium(items: Item[]): number {
  let total = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (BASE_PREMIUMS[item.type] !== undefined) {
      total += BASE_PREMIUMS[item.type];
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
