interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface ScenarioResult {
  results: { premium: number }[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;
const INITIAL_ASSESSMENT_RATE = 0.1;
const PROCESSING_FEE = 5;

function calculateBasePremium(items: Item[]): number {
  let total = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    const mainItemPremium = BASE_PREMIUMS[item.type];
    if (mainItemPremium !== undefined) {
      total += mainItemPremium;
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
    const remainder = count % BUILDING_BLOCK_SIZE;
    total += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }

  return total;
}

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const basePremium = calculateBasePremium(step.items);
    const initialAssessmentSurcharge = Math.ceil(basePremium * INITIAL_ASSESSMENT_RATE);
    const premium = basePremium + initialAssessmentSurcharge + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

