    }
    quoteCount++;
    premium += PROCESSING_FEE;
    const insuranceSum = calculateInsuranceSum(step.items);
    policies.set(stepIndex, {
      insuranceSum,
      remainingCap: insuranceSum * 2,
      items: step.items,
    });
    return { premium };
  });
  return { results };
}

